import { Box, Drawer, List, ListItem, ListItemIcon, ListItemText, makeStyles } from '@material-ui/core'
import { AddCircle, Dashboard, PlaylistAddCheck } from '@material-ui/icons';
import urslogo from '../images/urslogo.png'
import React from 'react'


const drawerWidth = 200;

const useStyle = makeStyles(theme => ({
    root: {
        display: 'flex'
    },
    page: {
        background: '#f9fbfd',
        width: '100%'
    },
    sidebar: {
        width: drawerWidth
    },
    sidebarSpace: {
        width: drawerWidth,
        background: '#162276',
        color: '#ffffff'
    },
    logoContainer: {
        maxWidth: '50px',
        margin: '5px auto'
    },
    logo: {
        width: '100%',
        paddingTop: '10%'
    },
    lists: {
        margin: '0 auto'
    }
}));


export default function Layout({ children }) {
    const classes = useStyle()

    const sideLinks = [
        {
            text: 'Dashboard',
            icon: <Dashboard color='error' />,
            path: '/studentDashboard'
        },
        {
            text: 'Subjects',
            icon: <PlaylistAddCheck color='error' />,
            path: '/studentDashboard'
        },
        {
            text: 'Join a Class',
            icon: <AddCircle color='error' />,
            path: '/studentDashboard'
        },
    ]

    return (
        <div className={classes.root}>
            {/* // appbar */}

            {/* // sidebar */}

            <Drawer
                className={classes.sidebar}
                variant='permanent'
                anchor='left'
                classes={{ paper: classes.sidebarSpace }}
            >
                <div className={classes.logoContainer}>
                    <Box >
                        <img className={classes.logo} src={urslogo} alt="URSAC Online logo" />
                    </Box>
                </div>
                {/* List links */}
                <List className={classes.lists}>
                    {sideLinks.map(sideLink => (
                        <ListItem button key={sideLink.text}>
                            
                                <ListItemIcon>
                                    {sideLink.icon}
                                </ListItemIcon>
                                <ListItemText>
                                    {sideLink.text}
                                </ListItemText>
                        </ListItem>
                    ))}
                </List>

            </Drawer>

            <div className={classes.page}>
                {children}
            </div>
        </div>
    )
}
